var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"SHIELD_ADMIN_NAMED_NULL","text":{"KOREA":"예고르, 저거 보이나?","JPN":"イェゴール、あれが見えるか？","ENG":"Are you seeing what I'm seeing, Yegor?","TWN":"伊高爾，你有看到了嗎？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"음......?","JPN":"む……？","ENG":"Huh?","TWN":"嗯……？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"내가 아는 그게 맞나? 왜 이런 곳에 있지?","JPN":"こりゃ何の冗談だ？　あれがなぜこんなところにいやがるんだ？","ENG":"Is that what I think it is? What's it doing here?","TWN":"那是我所知道的那個吧？那東西為什麼會在這裡？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"SHIELD_ADMIN_NAMED_NULL","text":{"KOREA":"우리 생각이 서로 같나 보군.","JPN":"俺の見間違いであってほしかったが、やはり……","ENG":"Yeah, I think we're in agreement here.","TWN":"看來我們想的一樣。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_TOUCH"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SHIELD_ADMIN_NAMED_NULL","text":{"KOREA":"틀림없어. 기신급 육전병기 2번, <color=#ffd34c>크로노스</color>다.","JPN":"あれは機神級陸戦兵器第2番、<color=#ffd34c>クロノス</color>だ。","ENG":"There's no mistaking it. It's the god-class ground combat vehicle no. 2, a.k.a. <color=#ffd34c>Chronos</color>.","TWN":"不會錯的。正是機神級陸戰兵器2號，<color=#ffd34c>克羅諾斯</color>。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SHIELD_ADMIN_NAMED_NULL","text":{"KOREA":"외장 파츠가 없는 메인 프레임뿐이지만, 지원이 없으면 조금 까다로운 녀석이야.","JPN":"幸い外装パーツはなくメインフレームだけだが、\\nバックアップがなければちょいとばかり厄介な相手だ。","ENG":"It's only the default configuration without the attachments, but it'll be pretty tricky to take down without fire support.","TWN":"雖然只是一個沒有外裝部件的主機，但如果沒有支援，會稍微有點棘手。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"조금? 병기개발국에서 <color=#ffd34c>다 쓸어 버리는 불사신 괴물</color>이라고 불렀던 것 같은데?","JPN":"ちょいとだって？　兵器開発局じゃ<color=#ffd34c>万物をなぎ払う不死身の怪物</color>と\\n呼ばれてなかったか？","ENG":"Pretty tricky? I remember hearing someone from the Weapon Development Bureau say that it's an <color=#ffd34c>immortal monster of total destruction</color>…","TWN":"有點？那玩意不是被兵器開發局稱為<color=#ffd34c>橫掃一切的不死怪物</color>嗎？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SHIELD_ADMIN_NAMED_NULL","text":{"KOREA":"정면 승부는 어렵겠어. 우회 기동을 해야 하나?","JPN":"正面からの勝負は分が悪い。迂回すべきか？","ENG":"We won't be able to face it head-on. Should we try to maneuver around it?","TWN":"正面交鋒是行不通的，要用迂回戰術嗎？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"지금 네 팔에서 촉수가 돋아나고 있는 것 같은데, 그러기엔 시간이 좀 부족하지 않아?","JPN":"おいお前、腕から触手が生えかけてるぞ。\\nそんな悠長には構えてられないぜ。","ENG":"I'm not sure if we've got time for that, not when you've got tentacles growing from your arm.","TWN":"你的手臂上已經長出觸手了，我看我們是沒有時間了。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SHIELD_ADMIN_NAMED_NULL","text":{"KOREA":"으음...... 난제로군.","JPN":"むう……進退ここに窮まったか？","ENG":"Hmm... Well, this does put us in a quandary.","TWN":"嗯……真難辦啊。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"물러서라, 대원들.","JPN":"総員、下がっていろ。","ENG":"Stand back.","TWN":"退下，隊員們。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SHIELD_ADMIN_NAMED_NULL","text":{"KOREA":"전대장님?","JPN":"戦隊長？","ENG":"Commander?","TWN":"隊長？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"저 기체는 내가 상대한다. 걱정 말고 도플갱어들만 처리하도록.","JPN":"あの機体の相手は私が務める。\\nお前たちはドッペルゲンガーの撃退に専念しろ。","ENG":"I will fight the robot. The rest of you can focus on the Doppelgangers.","TWN":"我來對付那個機體，你們不用擔心我，去解決二重身吧。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"무슨 말씀이십니까?","JPN":"本気ですか？","ENG":"What are you talking about?","TWN":"您在說什麼？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"저건 그 <color=#ffd34c>다 쓸어 버리는 불사신 괴물</color>입니다.","JPN":"あれは例の<color=#ffd34c>万物をなぎ払う不死身の怪物</color>です。","ENG":"That's the <color=#ffd34c>immortal monster of total destruction</color>.","TWN":"那可是<color=#ffd34c>橫掃一切的不死怪物</color>啊。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"이전에 그 얘기를 들었을 때부터 흥미 있었다.","JPN":"かつてその二つ名を聞いたときから興味があったのだ。","ENG":"That's precisely why I've been so intrigued by it since I first heard about it.","TWN":"我以前聽到這件事時，早就對那東西很感興趣了。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"특히 저 장사정포는 듣던 대로 압권이군. 역시 사내의 포부와 화포는 크면 클수록 좋아.","JPN":"特にあの長射程砲は噂に違わぬ圧巻ぶりだな。\\nやはり漢の志と銃砲は大きいに限る。","ENG":"That long-range artillery is as impressive as I've heard. It's like what they say... Size does matter.","TWN":"尤其是那個長射程火砲，真是壯觀。果然，抱負和大砲都是越大越好。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"누구 친구 분 아니랄까 봐 취향 참......","JPN":"類は友を呼ぶというが、まったくいい趣味をしてらっしゃる……","ENG":"You sure sound like your friend...","TWN":"不愧是某人的朋友，這品味……"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"하지만 화력의 1인자는 누가 뭐래도 우리 포격 전대, 메이즈다!","JPN":"だが、火力最強の座に君臨するのは我が砲撃戦隊メイズである！","ENG":"But no one can outdo us in terms of firepower. We're the Maze Division!","TWN":"但不管怎麼說，論火力，我們梅茲炮擊戰隊才是第一！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"지금부터 그 사실을 증명해 주지!","JPN":"その歴然たる事実を証明してみせよう！","ENG":"Let's show them what we mean by that!","TWN":"就讓我們來證明吧！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};